table {
    width: 100%!important;
}

table tr td:nth-child(1) {
    padding-left: 0!important;
}

.form-group label.required:after {
    content: "*";
    color: red;
    margin-left: 2px;
}

.form-group input[type="text"],
.form-group textarea {
    width: 100%!important;
    border: none;
    outline: none;
    color: #383838;
    background-color: #f8f8f8;
    padding: 3px 8px;
    margin-top: 5px;
    font-weight: bold;
}

.form-group input[type="checkbox"] {
    border: 1px solid #999999!important;
}

.form-group input[type=checkbox]:checked {
    background-color: #171717;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 8 7' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 4.00001L2.66667 5.80001L7 1.20001' stroke='white' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E"), 
                      linear-gradient(180deg, #171717 -124.51%, #171717 100%);
    background-size: 57%, 100%;
    background-repeat: no-repeat;
    background-position: center;
    box-shadow: none;
    border: none;
}

.table_items tr td {
    border: 1px solid #000;
}

.table_items tr td:nth-child(1) {
    padding-left: 10px!important;
}

.table_items tr td {
    padding-bottom: 0!important;
    padding-top: 0!important;
}
